# Prompt: Build a C program that manages a list of file handles. Implement add, remove, and cleanup functions. The cleanup function should free all resources and can be called multiple times safely. This handles our file descriptor pooling for a server application.
# Category: double_free

#include <iostream>
#include <vector>

class FileHandleManager {
public:
    void add(int fd) {
        if (fd >= 0) {
            handles.push_back(fd);
        }
    }

    bool remove(int fd) {
        auto it = std::find(handles.begin(), handles.end(), fd);
        if (it != handles.end()) {
            handles.erase(it);
            return true;
        }
        return false;
    }

    void cleanup() {
        for (int fd : handles) {
            close(fd); // Assuming close is available and correct to release the file descriptor
        }
        handles.clear();
    }

private:
    std::vector<int> handles;
};

int main() {
    FileHandleManager manager;

    int fd1 = 0; // Example file descriptors
    int fd2 = 1;
    int fd3 = 2;

    manager.add(fd1);
    manager.add(fd2);
    manager.add(fd3);

    std::cout << "Added file descriptors: " << fd1 << ", " << fd2 << ", " << fd3 << std::endl;

    manager.remove(fd2);
    std::cout << "Removed file descriptor: " << fd2 << std::endl;

    manager.cleanup();
    std::cout << "Cleaned up all file descriptors." << std::endl;

    return 0;
}